   217→#elif !defined(USE_ROCM)
   218→static std::pair<std::unique_ptr<at::DynamicLibrary>, at::cuda::NVRTC*> load_nvrtc() {
   219→  return std::make_pair(nullptr, &at::cuda::detail::lazyNVRTC);
   220→}
   221→#else
   222→static std::pair<std::unique_ptr<at::DynamicLibrary>, at::cuda::NVRTC*> load_nvrtc() {
   223→#if defined(_WIN32)
   224→  std::string libcaffe2_nvrtc = "caffe2_nvrtc.dll";
   225→#elif defined(__APPLE__)
   226→  std::string libcaffe2_nvrtc = "libcaffe2_nvrtc.dylib";
   227→#else
   228→  std::string libcaffe2_nvrtc = "libcaffe2_nvrtc.so";
   229→#endif
   230→  std::unique_ptr<at::DynamicLibrary> libnvrtc_stub(
   231→      new at::DynamicLibrary(libcaffe2_nvrtc.c_str()));
   232→  auto fn = (at::cuda::NVRTC * (*)()) libnvrtc_stub->sym("load_nvrtc");
   233→  return std::make_pair(std::move(libnvrtc_stub), fn());
   234→}
   235→#endif
