   116→int64_t minimum_gemm_alignment(sdp_params const& params) {
   117→  auto dprops = at::cuda::getCurrentDeviceProperties();
   118→  bool is_half = (params.query.dtype() == at::kHalf) ||
   119→      (params.query.dtype() == at::kBFloat16);
   120→  bool use_tc = use_tensor_cores(params, dprops, is_half);
   121→  int64_t matmul_alignment_mn = 1;
   122→  if (dprops->major >= 8) {
   123→    matmul_alignment_mn = 4;
   124→  }
   125→  int64_t bits_per_scalar = is_half ? 16 : 32;
   126→  if (use_tc) {
   127→    matmul_alignment_mn = std::max(matmul_alignment_mn, 128 / bits_per_scalar);
   128→  }
   129→  return matmul_alignment_mn;
   130→}
