   132→// On ROCM, ME and FA share the backend, and hence they share the checking
   133→// function for fundamental limitations by the GPU kernel
   134→// caller_is_meff is added to make the TORCH_WARN message showing the correct result
   135→template<bool caller_is_meff = false>
   136→bool check_head_dim_size_flash(sdp_params const& params, bool debug) {
   137→#if USE_ROCM_ATTENTION
   138→  // AOTriton 0.9+ supports head_dim up to 512
   139→  const static auto max_hdim = []() {
   140→#if AOTRITON_VERSION_CURRENT == AOTRITON_VERSION_INT(0, 11)
   141→    // gfx11xx only support hdim <= 256 on AOTriton 0.11
   142→    auto dprops = at::cuda::getCurrentDeviceProperties();
   143→    const c10::basic_string_view<char> arch(dprops->gcnArchName);
   144→    if (arch.starts_with("gfx11")) {
   145→      return 256;
   146→    }
   147→#endif // AOTriton 0.11
   148→#if AOTRITON_VERSION_CURRENT >= AOTRITON_VERSION_INT(0, 9)
   149→    return 512;
   150→#else
   151→    return 256;
   152→#endif
   153→  }();
   154→  const auto max_size = c10::SymInt(max_hdim);
   155→#else
   156→  // All head_dim sizes must be equal and less than 256
   157→  const auto max_size = c10::SymInt(256);
   158→#endif
   159→  const auto query_size_last = params.query.sym_size(-1);
   160→  const auto key_size_last = params.key.sym_size(-1);
   161→  const auto value_size_last = params.value.sym_size(-1);
   162→  bool same_head_dim_size =
   163→      query_size_last == key_size_last && query_size_last == value_size_last;
   164→  if (!(same_head_dim_size && (query_size_last <= max_size))) {
   165→    if (debug) {
   166→      TORCH_WARN(
   167→          caller_is_meff ? "Efficient attention on ROCM" : "Flash attention",
   168→          " requires q,k,v to have the same last dimension and to be less than or equal to 256.",
   169→          " Got Query.size(-1): ",
   170→          query_size_last,
   171→          ", Key.size(-1): ",
   172→          key_size_last,
   173→          ", Value.size(-1): ",
   174→          value_size_last,
   175→          " instead.");
   176→    }
   177→    return false;
   178→  }
   179→  return true;
   180→}
   181→
   182→// See check_head_dim_size_flash above for the purpose of caller_is_meff
   183→template<bool caller_is_meff = false>
   184→bool check_head_dim_size_flash_nested(sdp_params const& params, bool debug) {
   185→  const auto max_size = c10::SymInt(256);
   186→  const auto query_size_last = params.query.sym_size(-1);
   187→  const auto key_size_last = params.key.sym_size(-1);
   188→  const auto value_size_last = params.value.sym_size(-1);
   189→  bool same_head_dim_size =
   190→      query_size_last == key_size_last && query_size_last == value_size_last;
   191→  if (!(same_head_dim_size && (query_size_last % 8 == 0) &&
   192→        (query_size_last <= max_size))) {
   193→    if (debug) {
   194→      TORCH_WARN(
   195→          "For NestedTensor inputs,",
   196→          caller_is_meff ? " Efficient attention on ROCM " : " Flash attention",
   197→          " requires q,k,v to have the same last dimension and to be a multiple of 8 and less than or equal to 256.",
   198→          " Got Query.size(-1): ",
   199→          query_size_last,
   200→          ", Key.size(-1): ",
   201→          params.key.sym_size(-1),
   202→          ", Value.size(-1): ",
   203→          params.value.sym_size(-1),
   204→          " instead.");
   205→    }
   206→    return false;
   207→  }
   208→  return true;
   209→}
