   236→template <int Major, int Minor>
   237→struct SMVersion {
   238→  static constexpr int major = Major;
   239→  static constexpr int minor = Minor;
   240→  constexpr SMVersion() = default;
   241→};
   242→
   243→/**
   244→ * Checks if the current CUDA device architecture is inclusively within the specified range.
   245→ *
   246→ * @param lower_bound The lower bound of the CUDA device architecture range.
   247→ * @param upper_bound The upper bound of the CUDA device architecture range.
   248→ * @param params The parameters for the current operation.
   249→ * @return True if the current CUDA device architecture is within the specified range, false otherwise.
   250→ */
   251→template <typename lower_bound, typename upper_bound>
   252→bool check_sm_version(cudaDeviceProp * dprops) {
   253→  bool is_gte_lower_bound = dprops->major > lower_bound::major ||
   254→      (dprops->major == lower_bound::major &&
   255→       dprops->minor >= lower_bound::minor);
   256→  bool is_lte_upper_bound = dprops->major < upper_bound::major ||
   257→      (dprops->major == upper_bound::major &&
   258→       dprops->minor <= upper_bound::minor);
   259→  return is_gte_lower_bound && is_lte_upper_bound;
   260→}
