   860→SDPBackend select_sdp_backend(sdp_params const& kernel_params) {
   861→  // This function defines the priority order of the different sdp backends
   862→  // 1. Flash Attention
   863→  // 2. Mem Efficient Attention
   864→  // 3. Math fallback
   865→  auto& ctx = at::globalContext();
   866→  if (!ctx.userEnabledMathSDP() && !ctx.userEnabledFlashSDP() &&
   867→      !ctx.userEnabledMemEfficientSDP() && !ctx.userEnabledCuDNNSDP()) {
   868→    return SDPBackend::error;
   869→  }
   870→  // Get ideal kernel ordering
   871→  const auto ordering = priority_order(kernel_params);
   872→
   873→  // Because TORCHCHECK checks if condition is true we negate debug so that
   874→  // The statements will be printed when debug is true
   875→  bool print_debug = false;
   876→  for (auto& backend : ordering) {
   877→    switch (backend) {
   878→      case SDPBackend::cudnn_attention:
   879→        if (sdp::can_use_cudnn_attention(kernel_params, print_debug)) {
   880→              return SDPBackend::cudnn_attention;
   881→        }
   882→        break;
   883→      case SDPBackend::flash_attention:
   884→        if (sdp::can_use_flash_attention(kernel_params, print_debug)) {
   885→          return SDPBackend::flash_attention;
   886→        }
   887→        break;
   888→      case SDPBackend::efficient_attention:
   889→        if (sdp::can_use_mem_efficient_attention(kernel_params, print_debug)) {
   890→          return SDPBackend::efficient_attention;
   891→        }
   892→        break;
   893→      case SDPBackend::math:
   894→        if (ctx.userEnabledMathSDP()) {
   895→          return SDPBackend::math;
   896→        }
   897→        break;
   898→      case SDPBackend::overrideable:
   899→        if (ctx.userEnabledOverrideableSDP()) {
   900→          TORCH_CHECK(false, "Invalid backend");
   901→        }
   902→        break;
   903→      default:
   904→        TORCH_CHECK(false, "Invalid backend");
   905→    }
   906→  }
   907→  // If we have gotten to this point then two things have happened:
   908→  // 1. use_flash_attention or use_mem_efficient did not satisfy the
   909→  // constraints to be ran
   910→  // 2. The user has explicitly disabled the math kernel
   911→  // We then re-run the kernel checks with debug enabled to print out the
   912→  // reason why the kernel was not selected
   913→
   914→  print_debug = true;
   915→  TORCH_WARN("Memory efficient kernel not used because:");
   916→  sdp::can_use_mem_efficient_attention(kernel_params, print_debug);
   917→  TORCH_WARN("Flash attention kernel not used because:");
   918→  sdp::can_use_flash_attention(kernel_params, print_debug);
   919→  TORCH_WARN("cuDNN attention kernel not used because:");
   920→  sdp::can_use_cudnn_attention(kernel_params, print_debug);
   921→  TORCH_CHECK(!print_debug, "No available kernel. Aborting execution.")
   922→  return SDPBackend::error;
   923→}
