   925→bool check_for_seq_len_1_nested_tensor(sdp_params const& params, bool debug) {
   926→  // When this function is called we are assured that the nt is dim==4
   927→  if (!params.query.is_nested()) {
   928→    return true;
   929→  }
   930→
   931→  const auto nt_q_tensor_impl =
   932→      at::native::get_nested_tensor_impl(params.query);
   933→  const at::Tensor& sizes = nt_q_tensor_impl->get_nested_sizes();
   934→  auto* sizes_ptr = sizes.data_ptr<int64_t>();
   935→  const int64_t n_tensors = params.query.size(0);
   936→  const int64_t size_tensor_stride = sizes.stride(0);
   937→
   938→  // This is being called inside sdp with shape [batch, heads, {seq_len}, dim]
   939→  for (const auto i : c10::irange(n_tensors)) {
   940→    if (sizes_ptr[(i * size_tensor_stride) + 1] <= 1) {
   941→      if (debug) {
   942→        TORCH_WARN(
   943→            "Packed projection for fused kernels does not support sequence_length <= 1");
   944→      }
   945→      return false;
   946→    }
   947→  }
   948→
   949→  return true;
   950→}
