+#include <ATen/cuda/detail/CUDAHooks.h>
+
+#include <ATen/cuda/CUDAGeneratorImpl.h>
+#include <ATen/Context.h>
+#include <ATen/DeviceGuard.h>
+#include <ATen/DynamicLibrary.h>
